import{_ as o,o as i,c as l,ai as d}from"./chunks/framework.ampVZV4B.js";const u=JSON.parse('{"title":"工作沟通口语模板","description":"","frontmatter":{},"headers":[],"relativePath":"english-speaking/templates-work.md","filePath":"english-speaking/templates-work.md"}'),t={name:"english-speaking/templates-work.md"};function a(c,e,r,s,n,h){return i(),l("div",null,[...e[0]||(e[0]=[d('<h1 id="工作沟通口语模板" tabindex="-1">工作沟通口语模板 <a class="header-anchor" href="#工作沟通口语模板" aria-label="Permalink to “工作沟通口语模板”">​</a></h1><blockquote><p>这一篇适合工作、协作、汇报、催进度、说明问题等常见表达。<br> 重点不是高级词汇，而是<strong>简单、清楚、礼貌</strong>。</p></blockquote><hr><h2 id="_1-开始沟通-8-句" tabindex="-1">1. 开始沟通（8 句） <a class="header-anchor" href="#_1-开始沟通-8-句" aria-label="Permalink to “1. 开始沟通（8 句）”">​</a></h2><ol><li><code>I&#39;d like to discuss something with you.</code></li><li><code>Do you have a minute?</code></li><li><code>Can we talk about this for a moment?</code></li><li><code>I want to give you a quick update.</code></li><li><code>I need your input on this.</code></li><li><code>I&#39;d like to get your opinion.</code></li><li><code>Let&#39;s go over this together.</code></li><li><code>I want to make sure we&#39;re aligned.</code></li></ol><h2 id="_2-反馈进度-10-句" tabindex="-1">2. 反馈进度（10 句） <a class="header-anchor" href="#_2-反馈进度-10-句" aria-label="Permalink to “2. 反馈进度（10 句）”">​</a></h2><ol start="9"><li><code>I&#39;m working on it now.</code></li><li><code>I&#39;ve already started on it.</code></li><li><code>It&#39;s currently in progress.</code></li><li><code>I&#39;m almost done.</code></li><li><code>I&#39;ve completed the first part.</code></li><li><code>I&#39;m waiting for the final confirmation.</code></li><li><code>We are on schedule.</code></li><li><code>We&#39;re making good progress.</code></li><li><code>There are still a few things to finish.</code></li><li><code>I expect to finish it by tomorrow.</code></li></ol><h2 id="_3-说明问题-10-句" tabindex="-1">3. 说明问题（10 句） <a class="header-anchor" href="#_3-说明问题-10-句" aria-label="Permalink to “3. 说明问题（10 句）”">​</a></h2><ol start="19"><li><code>We&#39;re facing a small issue here.</code></li><li><code>There seems to be a problem.</code></li><li><code>I found a bug in the system.</code></li><li><code>The result is not what we expected.</code></li><li><code>Something is blocking the progress.</code></li><li><code>We&#39;re missing some information.</code></li><li><code>The data doesn&#39;t look correct.</code></li><li><code>This part needs to be checked again.</code></li><li><code>There may be a risk here.</code></li><li><code>We need to fix this before moving on.</code></li></ol><h2 id="_4-请求支持-10-句" tabindex="-1">4. 请求支持（10 句） <a class="header-anchor" href="#_4-请求支持-10-句" aria-label="Permalink to “4. 请求支持（10 句）”">​</a></h2><ol start="29"><li><code>Could you take a look at this?</code></li><li><code>Can you help me review this part?</code></li><li><code>I need your support on this issue.</code></li><li><code>Could you confirm this for me?</code></li><li><code>Would you mind checking it again?</code></li><li><code>Can we get some help from the team?</code></li><li><code>Could you share your thoughts on this?</code></li><li><code>I need more details before I continue.</code></li><li><code>Please let me know what you think.</code></li><li><code>I&#39;d appreciate your feedback.</code></li></ol><h2 id="_5-对齐信息-10-句" tabindex="-1">5. 对齐信息（10 句） <a class="header-anchor" href="#_5-对齐信息-10-句" aria-label="Permalink to “5. 对齐信息（10 句）”">​</a></h2><ol start="39"><li><code>Just to make sure we&#39;re on the same page.</code></li><li><code>Let me summarize the current situation.</code></li><li><code>Here&#39;s my understanding so far.</code></li><li><code>Please correct me if I&#39;m wrong.</code></li><li><code>So the next step is clear.</code></li><li><code>Let&#39;s confirm the priority first.</code></li><li><code>We should align on the timeline.</code></li><li><code>Let&#39;s agree on the scope.</code></li><li><code>We need a clear owner for this task.</code></li><li><code>Let&#39;s define the next action item.</code></li></ol><h2 id="_6-礼貌催办-10-句" tabindex="-1">6. 礼貌催办（10 句） <a class="header-anchor" href="#_6-礼貌催办-10-句" aria-label="Permalink to “6. 礼貌催办（10 句）”">​</a></h2><ol start="49"><li><code>Just following up on this.</code></li><li><code>Do you have any updates on this?</code></li><li><code>Could you let me know the current status?</code></li><li><code>I wanted to check if there&#39;s any progress.</code></li><li><code>When do you think this will be ready?</code></li><li><code>Could you send it to me once it&#39;s done?</code></li><li><code>Please keep me posted.</code></li><li><code>This is a gentle reminder.</code></li><li><code>It would be great if we could move this forward today.</code></li><li><code>Please let me know if anything is blocking you.</code></li></ol><h2 id="_7-表达建议-10-句" tabindex="-1">7. 表达建议（10 句） <a class="header-anchor" href="#_7-表达建议-10-句" aria-label="Permalink to “7. 表达建议（10 句）”">​</a></h2><ol start="59"><li><code>I have a suggestion.</code></li><li><code>Maybe we can try another approach.</code></li><li><code>It might be better to do it this way.</code></li><li><code>What if we simplify this part?</code></li><li><code>I think we should focus on the key issue first.</code></li><li><code>We may want to review this again.</code></li><li><code>It would help if we clarified the requirement first.</code></li><li><code>I recommend starting with the smaller task.</code></li><li><code>Let&#39;s keep the solution simple for now.</code></li><li><code>We can improve it in the next iteration.</code></li></ol><h2 id="_8-收尾表达-12-句" tabindex="-1">8. 收尾表达（12 句） <a class="header-anchor" href="#_8-收尾表达-12-句" aria-label="Permalink to “8. 收尾表达（12 句）”">​</a></h2><ol start="69"><li><code>Thanks for the update.</code></li><li><code>That sounds good to me.</code></li><li><code>Let&#39;s move forward with this plan.</code></li><li><code>I&#39;ll take care of the next step.</code></li><li><code>Please let me know if anything changes.</code></li><li><code>I&#39;ll keep you updated.</code></li><li><code>Let&#39;s stay in touch on this.</code></li><li><code>Thanks for your support.</code></li><li><code>I think we&#39;re in good shape now.</code></li><li><code>This should work for now.</code></li><li><code>Let&#39;s review it again tomorrow.</code></li><li><code>We can close this for now.</code></li></ol><hr><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to “使用建议”">​</a></h2><ul><li>工作口语里，<code>简洁</code> 比 <code>高级</code> 更重要</li><li>重点记 <code>19-38</code> 和 <code>49-58</code></li><li>把你自己常见的工作场景套进去练</li></ul>',22)])])}const p=o(t,[["render",a]]);export{u as __pageData,p as default};
